import { GoogleGenAI } from "@google/genai";
import type { FileContent, ModelName, LinkedFile } from '../types';

const getAiClient = () => {
  if (!process.env.API_KEY) {
    throw new Error("API_KEY environment variable not set");
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

async function fetchFileFromUrl(url: string): Promise<FileContent> {
  const response = await fetch(url);
  const blob = await response.blob();
  const arrayBuffer = await blob.arrayBuffer();
  const base64 = btoa(
    new Uint8Array(arrayBuffer).reduce((data, byte) => data + String.fromCharCode(byte), "")
  );
  return {
    mimeType: blob.type || 'application/pdf',
    data: base64,
  };
}

async function linkedFileToGenerativePart(linked: LinkedFile): Promise<FileContent> {
  if (linked.file) {
    const reader = new FileReader();
    const data = await new Promise<string>((resolve) => {
      reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
      reader.readAsDataURL(linked.file!);
    });
    return { mimeType: linked.file.type, data };
  } else if (linked.url) {
    return await fetchFileFromUrl(linked.url);
  }
  throw new Error("Invalid LinkedFile: No file or URL provided");
}

export async function searchScoringCriteria(university: string, year: string, model: ModelName): Promise<string> {
  const ai = getAiClient();
  const examInfo = `${university} ${year}`;
  const prompt = `
    You are an expert AI assistant.
    Find the official scoring criteria or model answers for the following math essay exam: "${examInfo}".
    Output ONLY the criteria in Korean markdown format.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: { tools: [{ googleSearch: {} }] },
  });

  let text = response.text?.trim() || "";
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    const uniqueLinks = new Set<string>();
    let sourceText = "\n\n### 참고 자료 (Google Search)\n";
    let hasSources = false;
    chunks.forEach((chunk: any) => {
      if (chunk.web?.uri && chunk.web?.title && !uniqueLinks.has(chunk.web.uri)) {
        uniqueLinks.add(chunk.web.uri);
        sourceText += `- [${chunk.web.title}](${chunk.web.uri})\n`;
        hasSources = true;
      }
    });
    if (hasSources) text += sourceText;
  }
  return text;
}

export async function gradeSolutionAndGenerateFeedback(
  commonData: { university: string; examYear: string; scoringCriteria: string; model: ModelName; problemMaterials: LinkedFile[]; scoringMaterials: LinkedFile[] },
  studentData: { name: string; solutionFiles: File[]; reportTemplate: string }
): Promise<string> {
  const ai = getAiClient();
  const examInfo = `${commonData.university} ${commonData.examYear}`;

  // 모든 자료 통합 (문제 + 해설)
  const allReferenceParts = await Promise.all([
    ...commonData.problemMaterials.map(l => linkedFileToGenerativePart(l)),
    ...commonData.scoringMaterials.map(l => linkedFileToGenerativePart(l))
  ]);

  const studentSolutionParts = await Promise.all(
    studentData.solutionFiles.map(file => {
      const reader = new FileReader();
      return new Promise<FileContent>((resolve) => {
        reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
        reader.readAsDataURL(file);
      });
    })
  );

  const prompt = `
    You are '수리논술 도우미'. Evaluate student solutions based on provided materials.
    - Student: ${studentData.name}
    - Exam: ${examInfo}
    - Scoring Criteria: ${commonData.scoringCriteria}
    ${studentData.reportTemplate ? `- Instructions: ${studentData.reportTemplate}` : ''}

    # Output Structure (Korean Markdown):
    ## 총점
    ## 채점 기준별 상세 점수 (Table)
    ## 문제별 상세 평가 (강점, 약점, 모범 답안)
    ## 총평
    ## 개선을 위한 피드백

    Rules:
    1. Use LaTeX ($...$) for ALL math and numbers.
    2. Focus on the 'Scoring/Solution Materials' provided in the input parts for accurate grading.
  `;

  const config: any = { tools: [{ googleSearch: {} }] };
  if (commonData.model.includes('pro')) config.thinkingConfig = { thinkingBudget: 16000 };
  else config.thinkingConfig = { thinkingBudget: 4000 };

  const response = await ai.models.generateContent({
    model: commonData.model,
    contents: {
      parts: [
        { text: prompt },
        ...allReferenceParts.map(p => ({ inlineData: p })),
        ...studentSolutionParts.map(p => ({ inlineData: p })),
      ],
    },
    config,
  });

  return response.text || "";
}

export async function formatReportToHtml(rawReport: string, commonData: { university: string; examYear: string; model: ModelName }, studentName: string, generationDate: string): Promise<string> {
  const ai = getAiClient();
  const prompt = `Convert this math report to a beautiful Tailwind CSS HTML document (stone-900 theme). Preserve LaTeX ($...$). Date: ${generationDate}, Student: ${studentName}, Exam: ${commonData.university} ${commonData.examYear}\n\nReport:\n${rawReport}`;
  const response = await ai.models.generateContent({ model: commonData.model, contents: prompt });
  return (response.text || "").replace(/```html|```/g, "").trim();
}

export async function extractReportData(rawReport: string, model: ModelName) {
  const ai = getAiClient();
  const prompt = `Extract JSON data: totalScore, maxScore, weaknesses[], strengths[], conceptWeaknesses[{concept, category, count, details[]}], coreCompetencies{problemSolving, writingAbility, calculationAccuracy}, criteriaScores[]. Report:\n${rawReport}`;
  const response = await ai.models.generateContent({ model, contents: prompt, config: { responseMimeType: "application/json" } });
  return JSON.parse(response.text || "{}");
}

