          localStorage.setItem(storageKey, JSON.stringify(history));
          saveToGoogleSheets({
            studentId: student.id, studentName: student.name, date: generationDate, examInfo: `${formData.university} ${formData.examYear}`,
            ...extracted
          });
        } catch (ee) {}

        const reportData: ReportData = {
          htmlContent: htmlReport,
          studentEmail: student.email,
          studentName: student.name,
          examInfo: `${formData.university} ${formData.examYear}`,
          generationDate
        };

        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, status: 'done', data: reportData, progressMessage: undefined } : r));
      } catch (e) {
        const message = e instanceof Error ? e.message : '오류 발생';
        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, status: 'error', error: message, progressMessage: undefined } : r));
      }
    }
    setIsLoading(false);
  }, [formData]);

  const handleFormChange = (newFormData: Partial<FormData>) => setFormData(prev => ({ ...prev, ...newFormData }));

  return (
    <div className="min-h-screen w-full font-sans flex flex-col">
      <header className="sticky top-0 z-10 bg-stone-900/50 backdrop-blur-md border-b border-stone-800">
        <div className="container mx-auto px-6 py-4">
          <h1 className="text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-sky-400 to-fuchsia-500">
            수리논술 AI 채점 센터
          </h1>
        </div>
      </header>

      <main className="container mx-auto p-6 grid grid-cols-1 lg:grid-cols-2 gap-8 flex-grow items-start">
        <div className="lg:sticky top-24">
          <InputForm
            formData={formData}
            onFormChange={handleFormChange}
            onGenerate={handleGenerateReport}
            onSearchCriteria={handleSearchCriteria}
            isLoading={isLoading}
            isSearching={isSearching}
          />
        </div>
        <div>
          {results.length === 0 ? <ReportPlaceholder /> : (
            <div className="bg-stone-900/50 border border-stone-800 rounded-xl shadow-2xl overflow-hidden backdrop-blur-lg">
              <div className="p-4 border-b border-stone-800 bg-stone-900/40">
                <h2 className="font-bold text-stone-100">채점 결과 리스트 ({progress.current}/{progress.total})</h2>
              </div>
              <div className="p-2 space-y-2">
                {results.map(r => (
                  <details key={r.studentId} className="bg-stone-800/40 rounded-lg overflow-hidden" open={r.status !== 'loading'}>
                    <summary className="p-4 flex justify-between items-center cursor-pointer hover:bg-stone-700/30 transition">
                      <span className="font-bold text-stone-200">{r.studentName}</span>
                      <div className="flex items-center gap-3">
                         {r.status === 'done' && <button onClick={(e) => { e.stopPropagation(); setSelectedStudentForProgress({id: r.studentId, name: r.studentName}); }} className="text-[10px] bg-sky-900/50 text-sky-400 px-2 py-1 rounded border border-sky-800">발전분석</button>}
                         {r.status === 'loading' ? <span className="text-xs text-sky-400 animate-pulse">{r.progressMessage}</span> : 
                          r.status === 'done' ? <CheckCircleIcon className="w-5 h-5 text-green-500" /> : <ExclamationCircleIcon className="w-5 h-5 text-red-500" />}
                      </div>
                    </summary>
                    <div className="border-t border-stone-800">
                      {r.status === 'done' && r.data && <ReportDisplay reportData={r.data} />}
                    </div>
                  </details>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>

      {selectedStudentForProgress && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
           <div className="bg-stone-900 border border-stone-800 w-full max-w-2xl max-h-[90vh] overflow-y-auto rounded-2xl shadow-2xl">
              <div className="sticky top-0 bg-stone-900 p-4 border-b border-stone-800 flex justify-between items-center">
                 <h2 className="font-bold text-stone-100">학습 데이터 분석</h2>
                 <button onClick={() => setSelectedStudentForProgress(null)} className="text-stone-500 hover:text-stone-100 text-xl">×</button>
              </div>
              <div className="p-6">
                 <StudentProgressView studentId={selectedStudentForProgress.id} studentName={selectedStudentForProgress.name} />
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

