const FileInputField: React.FC<{
  label: string;
  files: LinkedFile[];
  onFilesChange: (files: LinkedFile[]) => void;
  name: string;
  description: string;
}> = ({ label, files, onFilesChange, name, description }) => {
  const handleUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      // Fix: Added explicit type (f: File) to handle mapping from FileList which can sometimes lose type inference.
      const newFiles = Array.from(e.target.files).map((f: File) => ({ name: f.name, file: f }));
      onFilesChange([...files, ...newFiles]);
    }
  };

  return (
    <div className="space-y-2">
      <label className="block text-sm font-medium text-stone-400">{label}</label>
      <p className="text-xs text-stone-500">{description}</p>
      <div className="flex flex-wrap gap-2">
        {files.map((f, i) => (
          <div key={i} className="flex items-center bg-stone-800 px-3 py-1.5 rounded-lg border border-stone-700 text-xs">
            {f.url ? (
              <a href={f.url} target="_blank" rel="noreferrer" className="text-sky-400 hover:underline mr-2 truncate max-w-[120px]">{f.name}</a>
            ) : (
              <span className="text-stone-300 mr-2 truncate max-w-[120px]">{f.name}</span>
            )}
            <button onClick={() => onFilesChange(files.filter((_, idx) => idx !== i))} className="text-stone-500 hover:text-red-400">
              <TrashIcon className="w-3 h-3" />
            </button>
          </div>
        ))}
        <label className="cursor-pointer bg-stone-900 border border-dashed border-stone-700 px-3 py-1.5 rounded-lg text-xs text-stone-500 hover:border-sky-500 hover:text-sky-400 flex items-center">
          <UploadIcon className="w-3 h-3 mr-1" /> 추가
          <input type="file" className="sr-only" onChange={handleUpload} multiple />
        </label>
      </div>
    </div>
  );
};

