          const [univ, year, pUrl, sUrl] = row.split(',').map(s => s.trim());
          return { university: univ, year, problemUrl: pUrl, solutionUrl: sUrl };
        });
        localStorage.setItem('exam_database', JSON.stringify(db));
        alert(`${db.length}개의 시험 정보가 등록되었습니다.`);
